import React from "react";
import UploadImage from "./UploadImage";

function App() {
  return (
    <div className="min-h-screen bg-gray-100 flex flex-col items-center justify-center p-6">
      <h1 className="text-3xl font-bold text-gray-800 mb-4">Radiology AI App</h1>
      <p className="text-lg font-semibold text-gray-600 mb-4">Upload Medical Image for AI Analysis</p>

      <UploadImage />

      <div className="mt-6 w-full max-w-3xl bg-white shadow-lg p-6 rounded-lg">
        <h2 className="text-xl font-bold text-gray-800 mb-2">AI Report:</h2>
        <p className="text-gray-700 text-justify leading-relaxed">
          This image is a CT scan of the chest at the level of the lungs. Here's what I observe...
        </p>
      </div>
    </div>
  );
}

export default App;
